  {
    "$search": {
      "index": "default",
      "autocomplete": {
        "path": "plot",
        "query": "new purchase",
        "tokenOrder": "any",
        "fuzzy": {
          "maxEdits": 2,
          "prefixLength": 1,
          "maxExpansions": 256
        }
      },
      "highlight": {
          "path": "plot"
      }
    }
  },
  {
    "$limit": 5
  },
  {
    "$project": {
      "_id": 0,
      "title": 1,
      "plot": 1,
      "highlights": { "$meta": "searchHighlights" }
    }
  }
])
```

